function LSdkCpGt:UploadRole(roleType)
    local sServerId = gLGameLogin:GetServerId() or "0"
    local sServerName = gLGameLogin:GetServerName() or ""
    local roleId = tostring(gLGameLogin:GetPlayerId()) or "0"
    local roleName = ""
    local roleLevel = 0

    if roleType == 1 then
        local playerData = gLGameLogin:GetPlayerData()
        if not playerData then return end
        roleName = playerData.name
        roleLevel = tonumber(playerData.level) or 0
    else
        roleName = gModelPlayer:GetPlayerName() or ""
        roleLevel = gModelPlayer:GetPlayerLv() or 0
    end

    --String - 触发场景 (CREATE_ROLE 创建角色，ENTER_GAME 进入游戏，LEVEL_UP 等级提升，UPDATE_ROLE 修改昵称)

    local action = ""
    if CS.IsWebGL() then
        if roleType == 1 then
            action = "CREATE_ROLE"
        elseif roleType == 2 then
            action = "ENTER_GAME"
        elseif roleType == 3 then
            action = "LEVEL_UP"
        elseif roleType == 4 then
            action = "UPDATE_ROLE"
        end
    end

    self._impl:SendCpNativeMessage("UploadRole", sServerId, sServerName, roleId, roleName, roleLevel, action)
end

function LSdkCpGt:IsDMMPlatform()
    if self._sPackageId == "503" or self._sPackageId == "504" then
        return true
    end
    return self._isDmm
end

