function LSdkCpGt:GetCurrency()
    if string.isempty(self._currency) then
        self:_InitCurrency()
    end
    return self._currency
end

function LSdkCpGt:_InitCurrency()
    local symbol, currency = self:_GetCurrencyParams()
    self._currencySymbol = symbol
    self._currency = currency
end

local _subNameToChannel = {
    ["gt3"] = "jpnchannel1"
}

function LSdkCpGt:GetProductParam(payPointRef)
    local produceCp = payPointRef.jpnchannel

    local pfTitle = LGameSettings.platformTitle
    local channelName = _subNameToChannel[pfTitle]
    if not string.isempty(channelName) then
        produceCp = payPointRef[channelName]
    end

    local money = payPointRef.jpyPayPoint
    return produceCp, money, "JPY"
end

function LSdkCpGt:OnInternalCreateOrderOk(orderData)
    local payData = orderData.payData
    local extraData = orderData.extraData
    local objJson = LxHttpHelper.CheckWebJson(CS.YXWebRet.ok, orderData.orderId)
    if (not objJson) then
        return
    end
    local platformGoodsId = extraData.produceCp or "" --品项id
    local sMoney = tostring(payData.money) --价格
    local currency = self._currency
    local sServerId = tostring(gLGameLogin:GetServerId() or 0)
    local sServerName = gLGameLogin:GetServerName() or ""
    local sRoleId = gModelPlayer:GetPlayerId() or 0
    local sRoleName = gModelPlayer:GetPlayerName() or ""
    local sOutOrderNo = tostring(objJson.msg) --真实的订单id
    local callBackStr = extraData.callBackInfo
    local productName = payData.productName or ""

    if CS.IsOSAndroid() then
        self._impl:SendCpNativeMessage(
            "Pay",
            platformGoodsId,
            sMoney,
            currency,
            sServerId,
            sServerName,
            sRoleId,
            sRoleName,
            sOutOrderNo,
            callBackStr
        )
    elseif CS.IsOSIos() then
        local goodsDes = ""
        local roleLevel = tostring(gModelPlayer:GetPlayerLv() or 0)
        self._impl:SendCpNativeMessage(
            "Pay",
            platformGoodsId,
            sMoney,
            currency,
            goodsDes,
            sOutOrderNo,
            callBackStr,
            sServerId,
            sServerName,
            sRoleId,
            sRoleName,
            roleLevel
        )
    elseif CS.IsWebGL() then
        local description = productName
        local skuName = productName
        local imageUrl = "https://mh-jp-client.hkstarpower.com/h5/proj/webroot/res/dmmproduct.jpg"
        local roleLevel = tostring(gModelPlayer:GetPlayerLv() or 0)
        local goodsId = payData.goodsId
        local welfareRef = gModelPay and gModelPay:GetWelfareRefByRefId(goodsId)
        if welfareRef then
            skuName = welfareRef.nameDmm or ""
            description = skuName
        end
        LogWarn("Pay Call productcp = "..tostring(platformGoodsId).." === smoney="..tostring(sMoney))
        self._impl:SendCpNativeMessage(
                "Pay",
                platformGoodsId,
                sMoney,
                currency,
                sServerId,
                sServerName,
                sRoleId,
                sRoleName,
                sOutOrderNo,
                callBackStr,
                description,
                skuName,
                imageUrl)
    end
end

