---@param name string bindGoogle , bindFacebook, bindEmail ， bindApple, bindDevice
function LSdkCpGt:GetBindState(name)
    if name == "visitor" then
        if table.keysize(self._bindList) > 0 then
            return false
        end
        return true
    end
    local bindName = G_bindMessageNameMap[name] or name
    if self._bindList[bindName] then
        return true
    end
    return false
end

