function LSdkCpGt:OnBindAccountResult(args)
    local isOk = toboolean(args[1])

    local sBindList = args[2] or ""
    local arr = string.split(sBindList, "_") or {}
    self._bindList = {}
    for k,v in ipairs(arr) do
        self._bindList[v] = v
    end

    local str = isOk and ccClientText(15070) or ccClientText(15071)
    GF.ShowMessage(str)
    FireEvent(EventNames.SDK_ACCOUNTBIND_RESULT)
end

function LSdkCpGt:OncancellationAccountResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        self._sUserId = ""
        self._isValidUser = false
        PJXCenter.GameMgr:SetGameEnvVar("GameDisableSdkLogin", "true")
        self:LogoutOk()
    end
end

function LSdkCpGt:OnSwitchAccountResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        self._sUserId = ""
        self._isValidUser = false
        self:LogoutOk()
    end
end

function LSdkCpGt:OnLoginResult(args)
    local isOk = toboolean(args[1])
    self._isValidUser = false
    if isOk then
        -- self._isValidUser = true
        self._sUserId = args[2]
        self._sToken = args[3]
        self._sUserName = args[4] or ""
        self._sEmail = args[5] or ""
        local sBindList = args[6] or ""
        local arr = string.split(sBindList, "_") or {}
        self._bindList = {}
        for k,v in ipairs(arr) do
            self._bindList[v] = v
        end
        --printInfoN2("LSdkCpGt", self._sUserId..self._sToken..self._sUserName..self._sEmail )
        --self:LoginOk()
        self:_InternalStartWebValidUser()
    else
        self._sUserId = ""
        self._sToken = ""
        self:LoginFailure()
    end
end

function LSdkCpGt:_InternalStopWebValidUser()
    if self._webReq then
        self._webReq:Destroy()
        self._webReq = nil
    end
end

function LSdkCpGt:_InternalStartWebValidUser()
    if string.isempty(self._sToken) then return end
    self._isValidUser = false
    local webReq = self._webReq
    if webReq and not webReq:IsDestroy() then
        if webReq:IsSameValidReqParam(self._sToken) then -- 同样的验证码
            if not webReq:IsFinished() or webReq:IsOK() then
                --正在请求或者，已经请求成功了获得了结果，不再请求
                return
            end
        end
    end

    self:_InternalStopWebValidUser()

    webReq = LCpWebReq:New()
    self._webReq = webReq

    webReq:SetValidReqParam(self._sToken)

    local sToken = self._sToken or ""
    --local sign = string.upper(CS.md5FromString(sToken..LGameLogin.AuthKey))
    local tokenTbl = {
        "token="..sToken,
        "userId="..self._sUserId,
        "username="..self._sUserName,
        "email="..self._sEmail,
    }
    local paramPart = table.concat(tokenTbl, "&")
    local params = "gaotu/loginverify.do?"..paramPart

    local urlList = gLGameLogin:GetServicesUrlList()
    --print("gt ServicesUrl: " .. url)

    webReq:StartReq(urlList, params, function (ret, result)
        if ret ~= CS.YXWebRet.ok then
            GF.ShowMessage(ccClientText(140))
            LogError("AuthCodeError ...")
            self:_InternalStopWebValidUser() --销毁可以进行下次验证
            self:LoginFailure()
        else
            local code = tostring(result.code)
            if(code == "0") then
                self._isValidUser = true
                self:LoginOk()
                print("gt sdk loginOk")
            else
                GF.ShowMessage(ccClientText(140))
                LogError("error AuthCode response code = "..tostring(code).."|"..tostring(result.data))
                self:_InternalStopWebValidUser() --销毁可以进行下次验证
                self:LoginFailure()
            end
        end
    end,true)
end

function LSdkCpGt:OnLogoutResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        local sUserId = args[2]
        if sUserId == self._sUserId then
            self._isValidUser = false
            self._sUserId = ""
            self:LogoutOk()
        end
    end
end

function LSdkCpGt:OnGetSdkInfoResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        local result = args[2]
        if not string.isempty(result) then
            local tbl = JSON.decode(result)
            if tbl and tbl.platform == "dmm" then
                self._isDmm = true
            end
        end

    end
end

return LSdkCpGt